```typescript
import OpenAI from "openai";

const client = new OpenAI({
  apiKey: "YOURAPIKEY",
  baseURL: "https://api.agipower.ai/v1",
});

async function responsesWithWebSearch() {
  // Non-streaming request
  const response = await client.responses.create({
    model: "openai/gpt-5.2",
    input:
      "What is the latest iPhone model this year? What new features does it have?",
    tools: [
      {
        type: "web_search",
        searchcontextsize: "high",
        user_location: {
          type: "approximate",
          country: "CN",
          timezone: "Asia/Shanghai",
        },
      },
    ],
  } as any);

  // Process output
  for (const item of response.output) {
    if (item.type === "message") {
      for (const content of item.content) {
        if (content.type === "output_text") {
          console.log(content.text);

          // Print citations
          if (content.annotations) {
            console.log("\nCitations:");
            content.annotations.forEach((annotation: any) => {
              if (annotation.type === "url_citation") {
                console.log(
                  `- ${annotation.urlcitation.title}: ${annotation.urlcitation.url}`,
                );
              }
            });
          }
        }
      }
    } else if (item.type === "websearchcall") {
      console.log(`\nWeb Search status: ${item.status}`);
    }
  }
}

// Streaming request
async function responsesWithWebSearchStream() {
  const stream = await client.responses.create({
    model: "openai/gpt-5.2",
    input: "What are the most important tech news today?",
    stream: true,
    tools: [
      {
        type: "websearchpreview",
        searchcontextsize: "medium",
      },
    ],
  } as any);

  for await (const event of stream) {
    if (event.type === "response.websearchcall.in_progress") {
      console.log("🔍 Searching...");
    } else if (event.type === "response.websearchcall.searching") {
      console.log("🔎 Searching...");
    } else if (event.type === "response.websearchcall.completed") {
      console.log("✅ Search completed");
    } else if (event.type === "response.output_text.delta") {
      process.stdout.write(event.delta);
    }
  }
}

responsesWithWebSearch();
```

